const raw = $json.stdout || $json.data || $json.response || '';
const now = new Date().toISOString();
const sizeMatch = raw.match(/^(\S+)\s+\.$/m) || raw.match(/^(\S+)\s+\/root\.openclaw\/workspace$/m) || raw.match(/^(\S+)\s+\.\//m);
const size = sizeMatch ? sizeMatch[1] : 'unknown';
const countMatch = raw.match(/^(\d+)$/m);
const files = countMatch ? countMatch[1] : 'unknown';
const blocks = [ { type: 'header', text: { type: 'plain_text', text: '🧮 Security Repo Size Daily' } }, { type: 'context', elements: [ { type: 'mrkdwn', text: `*Checked:* ${now}` }, { type: 'mrkdwn', text: `*Size:* ${size}` } ] }, { type: 'divider' }, { type: 'section', text: { type: 'mrkdwn', text: `*File count*\n${files}` } } ];
return [{ json: { checkedAt: now, slackText: `🧮 Security repo size daily: ${size}`, slackBlocks: blocks } }];
